const path = require('path');

const {
  BASENAME_REGEX,
  FOLDER_WITH_PARAMS_REGEX,
  FILE_WITH_PARAMS_REGEX,
  FOLDER_WITH_CATCH_ALL_REGEX,
  FILE_WITH_CATCH_ALL_REGEX,
  FILE_IN_ROOT_REGEX,
  NODE_SUBPATH_IMPORT_REGEX,
} = require('../../constants/regexs');
const { SCRIPT_EXTENSIONS } = require('../../constants/file');
const { getFileDeviceType } = require('./device');
const {
  pathHasAlias,
  getFilePathFromAlias,
  getFilePathFromSubpathImport,
} = require('../aliases');

/**
 * @param { string } filePath - Relative file path
 * @param { string } dir - Directory path use to resolve full path
 * @returns { string } File full path
 */
const getFileFullPath = (filePath, dir) => path.resolve(dir, filePath);

/**
 * @param { string } filePath - Relative file path
 * @param { string } dir - Directory path use to resolve full path
 * @returns { string } File full path with extension when it is an SCRIPT
 */
const getScriptFullPathWithExtension = (filePath, dir) => {
  if (NODE_SUBPATH_IMPORT_REGEX.test(filePath)) {
    return getFilePathFromSubpathImport(filePath, dir) ?? '';
  }

  const relativeFilePath = pathHasAlias(filePath)
    ? getFilePathFromAlias(filePath, dir)
    : filePath;

  const fullPath = getFileFullPath(relativeFilePath, dir);

  let res = '';

  SCRIPT_EXTENSIONS.find((ext) => {
    try {
      res = require.resolve(`${fullPath}.${ext}`);

      return true;
    } catch {
      try {
        res = require.resolve(`${fullPath}/index.${ext}`);

        return true;
      } catch {
        return false;
      }
    }
  });

  return res;
};

/**
 * @param { string } filePath - File path to analize
 * @returns { string } File basename
 *
 * @example
 * getFileBasename('home.mobile.js') => 'home'
 * getFileBasename('products/help.hooks.server.js') => 'help'
 */
const getFileBasename = (filePath) =>
  path
    .basename(filePath)
    .replace(BASENAME_REGEX, '')
    .replace(/^styles$/, 'index');

/**
 * @param { string } filePath - File path to analize
 * @returns { string } File directory
 *
 * @example
 * getFileDirname('home.mobile.js') => ''
 * getFileDirname('products/help.hooks.server.js') => 'products'
 * getFileDirname('help/categories/[id].js') => 'help/categories'
 */
const getFileDirname = (filePath) => path.dirname(filePath).replace(/^\./g, '');

/**
 * @param {string} file
 */
const getFileDetail = (file) => ({
  dirname: getFileDirname(file),
  basename: getFileBasename(file),
  deviceType: getFileDeviceType(file),
});

/**
 * @param {string} pathValue
 */
const getPathSegments = (pathValue) => pathValue.split('/');

/**
 * @param {string} pathValue
 */
const getPathSegmentsWithoutIndex = (pathValue) => {
  const segments = getPathSegments(pathValue);
  const lastSegment = segments[segments.length - 1];

  if (lastSegment.startsWith('index') || lastSegment.startsWith('styles')) {
    segments.pop();
  }

  return segments;
};

/**
 * @param {string} filePath
 * @param {string} route
 */
const getCatchAllMetadata = (filePath, route) => {
  const routeSegments = getPathSegments(route).filter(Boolean);

  if (!routeSegments.some((segment) => segment === '*')) {
    return null;
  }

  const filePathSegments =
    getPathSegmentsWithoutIndex(filePath).filter(Boolean);

  const params = [];

  filePathSegments.forEach((pathName) => {
    const [, optionalParam, requiredParam] =
      FOLDER_WITH_CATCH_ALL_REGEX.exec(pathName) ||
      FILE_WITH_CATCH_ALL_REGEX.exec(pathName) ||
      [];
    const param = optionalParam || requiredParam;

    if (param) {
      params.push(param);
    }
  });

  const routeWithOptionalSegments = routeSegments.reduce(
    (acc, segment, index) => {
      if (segment === '*' && filePathSegments[index].startsWith('[[...')) {
        return `${acc}/**`;
      }

      return `${acc}/${segment}`;
    },
    '',
  );

  return {
    params,
    regexRoute:
      routeWithOptionalSegments === route
        ? null
        : `^${routeWithOptionalSegments
            .replace(/\/\*\*/g, '/?(.*)?')
            .replace(/\/\*/g, '/(.*)')
            .replace(/\//g, '\\/')}\\/?$`,
  };
};

/**
 * @param { string } filePath - File path to analyze
 * @returns { boolean } Wether or not file has catch-all
 *
 * @example
 * checkIfFileHasCatchAll('home.mobile.js') => false
 * checkIfFileHasCatchAll('products/help.hooks.server.js') => false
 * checkIfFileHasCatchAll('products/[...param]/index.js') => true
 * checkIfFileHasCatchAll('products/[...param].scss') => true
 * checkIfFileHasCatchAll('help/categories/[[...param]].js') => true
 */
const checkIfFileHasCatchAll = (filePath) => {
  const segments = getPathSegments(filePath);
  const lastSegment = segments.pop();

  return (
    FILE_WITH_CATCH_ALL_REGEX.test(lastSegment) ||
    segments.some((segment) => FOLDER_WITH_CATCH_ALL_REGEX.test(segment))
  );
};

/**
 * @param { string } filePath - File path to analyze
 * @returns { boolean } Wether or not file has params
 *
 * @example
 * checkIfFileHasParams('home.mobile.js') => false
 * checkIfFileHasParams('products/help.hooks.server.js') => false
 * checkIfFileHasParams('products/[id]/index.js') => true
 * checkIfFileHasParams('products/[id].scss') => true
 * checkIfFileHasParams('help/categories/[id].js') => true
 */
const checkIfFileHasParams = (filePath) => {
  const segments = getPathSegments(filePath);
  const lastSegment = segments.pop();

  return (
    (FILE_WITH_PARAMS_REGEX.test(lastSegment) &&
      !FILE_WITH_CATCH_ALL_REGEX.test(lastSegment)) ||
    segments.some(
      (segment) =>
        FOLDER_WITH_PARAMS_REGEX.test(segment) &&
        !FOLDER_WITH_CATCH_ALL_REGEX.test(segment),
    )
  );
};

/**
 * @param { string } filePath - Relative file path
 * @returns { boolean } Wether or not the file is located in the directory's root
 */
const checkIfFileIsInRoot = (filePath) => FILE_IN_ROOT_REGEX.test(filePath);

module.exports = {
  getFileFullPath,
  getScriptFullPathWithExtension,
  getFileBasename,
  getFileDirname,
  getFileDetail,
  getPathSegments,
  getPathSegmentsWithoutIndex,
  getCatchAllMetadata,
  checkIfFileIsInRoot,
  checkIfFileHasCatchAll,
  checkIfFileHasParams,
};
